const table=layui.table,util=layui.util,form=layui.form;table.render({id:"sortTable",elem:"#sort",url:"/api/sort/list?user=my",page:!0,cols:[[{field:"sortId",title:"ID",width:100},{field:"content",title:"分类"},{title:"文章数量",templet:({articles:articles})=>articles.length},{title:"创建者",templet:({user:user})=>user.nickName},{title:"创建时间",templet:({createdAt:createdAt})=>util.toDateString(createdAt,"yyyy-MM-dd HH:mm:ss")},{title:"操作",templet:()=>'<a class="layui-btn layui-btn-xs" lay-event="edit">编辑</a>\n                        <a class="layui-btn layui-btn-danger layui-btn-xs" lay-event="del">删除</a>'}]]}),table.on("tool(sort)",(function(obj){"del"===obj.event?layer.confirm("删除操作不可恢复，确定删除吗？",index=>{layer.load(2),layer.close(index),axios({method:"delete",url:"/api/sort",params:{sortId:obj.data.sortId}}).then(({data:res})=>{layer.closeAll("loading"),0===res.code?($ryTools.notify({description:res.msg}),table.reload("sortTable")):$ryTools.notify({description:res.msg,type:"error"})})}):"edit"===obj.event&&layer.confirm("还没做呢",(function(index){layer.close(index)}))})),$ry(".add-sort").click(()=>{layer.open({type:1,title:"创建分类",area:"375px",content:$ry(".addSortFrom").html(),success:(layero,index)=>{form.render(),form.on("submit(form)",({field:data})=>{layer.load(2),layer.close(index),axios({method:"post",url:"/api/sort",data:Qs.stringify(data)}).then(({data:res})=>{layer.closeAll("loading"),0===res.code?($ryTools.notify({description:res.msg}),table.reload("sortTable")):$ryTools.notify({description:res.msg,type:"error"})})})}})});